$function$;

CREATE OR REPLACE FUNCTION uxlab.form_echo(p_name text DEFAULT ''::text, p_email text DEFAULT ''::text, p_role text DEFAULT ''::text, p_notes text DEFAULT ''::text)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
