    || '</section>'
    || '<section><h4>pgv.dl</h4>'
    || pgv.dl('Nom', 'Jean Dupont', 'Email', 'jean@example.com', 'Role', 'Admin', 'Statut', pgv.badge('actif', 'success'))
    || '</section>'
